import threading
from typing import Dict, Optional
from decimal import Decimal
from contextlib import contextmanager
from dataclasses import dataclass
from enum import Enum


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


@dataclass
class Transaction:
    transaction_id: str
    account_id: str
    amount: Decimal
    transaction_type: TransactionType
    target_account_id: Optional[str] = None


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class DuplicateTransactionError(Exception):
    pass


class FinancialTransactionProcessor:
    def __init__(self):
        self._accounts: Dict[str, Decimal] = {}
        self._locks: Dict[str, threading.RLock] = {}
        self._global_lock = threading.RLock()
        self._processed_transactions = set()
        self._transaction_lock = threading.RLock()
    
    def create_account(self, account_id: str, initial_balance: Decimal = Decimal('0')) -> None:
        with self._global_lock:
            if account_id not in self._accounts:
                self._accounts[account_id] = initial_balance
                self._locks[account_id] = threading.RLock()
    
    def get_balance(self, account_id: str) -> Decimal:
        with self._global_lock:
            if account_id not in self._accounts:
                raise AccountNotFoundError(f"Account {account_id} not found")
            with self._locks[account_id]:
                return self._accounts[account_id]
    
    @contextmanager
    def _acquire_account_locks(self, *account_ids):
        sorted_ids = sorted(set(account_ids))
        locks_acquired = []
        
        try:
            for account_id in sorted_ids:
                with self._global_lock:
                    if account_id not in self._locks:
                        raise AccountNotFoundError(f"Account {account_id} not found")
                    lock = self._locks[account_id]
                lock.acquire()
                locks_acquired.append(lock)
            yield
        finally:
            for lock in reversed(locks_acquired):
                lock.release()
    
    def _mark_transaction_processed(self, transaction_id: str) -> bool:
        with self._transaction_lock:
            if transaction_id in self._processed_transactions:
                return False
            self._processed_transactions.add(transaction_id)
            return True
    
    def process_deposit(self, transaction: Transaction) -> Decimal:
        if transaction.transaction_type != TransactionType.DEPOSIT:
            raise ValueError("Invalid transaction type for deposit")
        
        if not self._mark_transaction_processed(transaction.transaction_id):
            raise DuplicateTransactionError(f"Transaction {transaction.transaction_id} already processed")
        
        try:
            with self._acquire_account_locks(transaction.account_id):
                self._accounts[transaction.account_id] += transaction.amount
                return self._accounts[transaction.account_id]
        except Exception:
            with self._transaction_lock:
                self._processed_transactions.discard(transaction.transaction_id)
            raise
    
    def process_withdrawal(self, transaction: Transaction) -> Decimal:
        if transaction.transaction_type != TransactionType.WITHDRAWAL:
            raise ValueError("Invalid transaction type for withdrawal")
        
        if not self._mark_transaction_processed(transaction.transaction_id):
            raise DuplicateTransactionError(f"Transaction {transaction.transaction_id} already processed")
        
        try:
            with self._acquire_account_locks(transaction.account_id):
                if self._accounts[transaction.account_id] < transaction.amount:
                    raise InsufficientFundsError(
                        f"Insufficient funds in account {transaction.account_id}"
                    )
                self._accounts[transaction.account_id] -= transaction.amount
                return self._accounts[transaction.account_id]
        except Exception:
            with self._transaction_lock:
                self._processed_transactions.discard(transaction.transaction_id)
            raise
    
    def process_transfer(self, transaction: Transaction) -> tuple[Decimal, Decimal]:
        if transaction.transaction_type != TransactionType.TRANSFER:
            raise ValueError("Invalid transaction type for transfer")
        
        if transaction.target_account_id is None:
            raise ValueError("Target account required for transfer")
        
        if not self._mark_transaction_processed(transaction.transaction_id):
            raise DuplicateTransactionError(f"Transaction {transaction.transaction_id} already processed")
        
        try:
            with self._acquire_account_locks(transaction.account_id, transaction.target_account_id):
                if self._accounts[transaction.account_id] < transaction.amount:
                    raise InsufficientFundsError(
                        f"Insufficient funds in account {transaction.account_id}"
                    )
                
                self._accounts[transaction.account_id] -= transaction.amount
                self._accounts[transaction.target_account_id] += transaction.amount
                
                return (
                    self._accounts[transaction.account_id],
                    self._accounts[transaction.target_account_id]
                )
        except Exception:
            with self._transaction_lock:
                self._processed_transactions.discard(transaction.transaction_id)
            raise
    
    def process_transaction(self, transaction: Transaction):
        if transaction.transaction_type == TransactionType.DEPOSIT:
            return self.process_deposit(transaction)
        elif transaction.transaction_type == TransactionType.WITHDRAWAL:
            return self.process_withdrawal(transaction)
        elif transaction.transaction_type == TransactionType.TRANSFER:
            return self.process_transfer(transaction)
        else:
            raise ValueError(f"Unknown transaction type: {transaction.transaction_type}")